import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.servlet.ModelAndView;

@Controller
public class MfaBackupCodesController {

    @Autowired
    private UserDetailsService userDetailsService;

    @Autowired
    private AuthenticationManager authenticationManager;

    @GetMapping("/mfa-backup-codes")
    public ModelAndView getMfaBackupCodes() {
        return new ModelAndView("mfa-backup-codes");
    }

    @PostMapping("/mfa-backup-codes/generate")
    public ModelAndView generateMfaBackupCodes(@RequestParam String username) {
        // Generate backup codes for the user
        UserDetailsService.UserDetails user = userDetailsService.loadUserByUsername(username);
        List<String> backupCodes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String code = generateBackupCode();
            backupCodes.add(code);
        }
        user.setMfaBackupCodes(backupCodes);
        userDetailsService.saveUser(user);

        // Return the backup codes to the client
        return new ModelAndView("mfa-backup-codes", "backupCodes", backupCodes);
    }

    @PostMapping("/mfa-backup-codes/authenticate")
    public ModelAndView authenticateMfaBackupCode(@RequestParam String username, @RequestParam String code) {
        // Authenticate the user using the backup code
        UserDetailsService.UserDetails user = userDetailsService.loadUserByUsername(username);
        if (user.getMfaBackupCodes().contains(code)) {
            authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(username, null));
            return new ModelAndView("mfa-backup-codes", "success", true);
        } else {
            return new ModelAndView("mfa-backup-codes", "error", "Invalid backup code");
        }
    }
}